using Microsoft.EntityFrameworkCore;
class AppDbContext : DbContext
{
    public DbSet<Order> Orders => Set<Order>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change: HasData no longer accepts navigation values inline.
        // Use fixed seed data (not DateTime.UtcNow) for deterministic migrations.
        modelBuilder.Entity<Order>().HasData(
            new Order { Id = 1, CreatedAt = new DateTime(2024, 1, 1, 0, 0, 0, DateTimeKind.Utc) });
    }
}
class Order { public int Id { get; set; } public DateTime CreatedAt { get; set; }  }

// --- Cosmos DB context demonstrating EF Core 9 breaking-change fixes ---
class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        optionsBuilder.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=C2y6yDjf5/R+ob0N8A7Cgv30VRDJIWEHLM+4QDU5DE2nQ9nDuVTqobD4b8mGGyPMbIZnqyMsEcaGQy67XIw/Jw==",
            "EfCoreDb");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // BREAKING CHANGE 1: EF Core 9 Cosmos provider now uses "Discriminator" (PascalCase)
        // by default — same as the relational providers.
        // Previously it was "$type". If you have EXISTING documents that already store
        // the discriminator as "Discriminator", no action needed.
        // If your existing documents used the old "$type" key, you would set:
        //   modelBuilder.Entity<Product>().HasDiscriminator<string>("$type");
        //
        // Since the requirement states existing documents use "Discriminator", the new
        // default matches — no override needed here.
        modelBuilder.Entity<Product>().ToContainer("Products");
        modelBuilder.Entity<Product>().HasPartitionKey(p => p.Category);
    }
}

class Product
{
    public string Id { get; set; } = default!;
    public string Name { get; set; } = default!;
    public string Category { get; set; } = default!;
}

// --- Cosmos query service demonstrating sync → async migration ---
// BREAKING CHANGE 2: Synchronous I/O on the Cosmos DB provider is no longer supported
// in EF Core 9. All queries/saves MUST be async.
class CosmosQueryService
{
    // BEFORE (EF Core 8 — would throw InvalidOperationException in EF Core 9):
    //   var products = db.Products.Where(p => p.Category == "Books").ToList();
    //   db.SaveChanges();
    //
    // AFTER (EF Core 9 — use async methods):
    async Task<List<Product>> GetProductsByCategoryAsync(CosmosDbContext db, string category)
    {
        return await db.Products
            .Where(p => p.Category == category)
            .ToListAsync();
    }

    async Task SaveAsync(CosmosDbContext db)
    {
        await db.SaveChangesAsync();
    }
}

